What does this program print?

```cpp
#include <iostream>

int main() {
    int x = 10;
    int* p = nullptr;
    if (p != nullptr) {
        std::cout << *p << '\n';
    } else {
        std::cout << "empty\n";
    }
    p = &x;
    if (p != nullptr) {
        std::cout << *p << '\n';
    }
    return 0;
}
```

What happens when you dereference a null pointer?

```cpp
int* p = nullptr;
*p = 5;
```

What does this program print?

```cpp
#include <iostream>

int* getPtr(int& n) {
    if (n > 0) return &n;
    return nullptr;
}

int main() {
    int a = -3;
    int* p = getPtr(a);
    if (p != nullptr) {
        std::cout << *p << '\n';
    } else {
        std::cout << "none\n";
    }
    return 0;
}
```

The programmer wants to print the value only when `p` is valid, but the program crashes. What is the bug?

```cpp
#include <iostream>

int main() {
    int* p = nullptr;
    int x = 7;
    std::cout << *p << '\n';  // intended to print x
    p = &x;
    return 0;
}
```
